					Change: &plans.ResourceInstanceChange{
						Addr: addrs.Resource{
							Mode: addrs.ManagedResourceMode,
							Type: "test_instance",
							Name: "instance",
						}.Instance(addrs.NoKey).Absolute(addrs.RootModuleInstance),
